import SwiftUI
import AppKit
import AVFoundation

class BreakWarningWindow: NSWindow {
    var countdownTimer: Timer?
    var onCountdownFinish: \(\(\) -> Void\)?
    var onCancelled: \(\(\) -> Void\)?

    init\(onCountdownFinish: @escaping \(\) -> Void, onCancelled: @escaping \(\) -> Void\) {
        super.init\(
            contentRect: NSRect\(x: 0, y: 0, width: 400, height: 200\),
            styleMask: [.titled, .closable],
            backing: .buffered,
            defer: false
        \)

        self.onCountdownFinish = onCountdownFinish
        self.onCancelled = onCancelled

        self.title = "休息提醒"
        self.level = .floating
        self.isOpaque = false
        self.backgroundColor = .clear
        self.center\(\)

        let contentView = BreakWarningView\(
            countdownSeconds: 3,
            onContinue: { [weak self] in
                self?.handleCancel\(\)
            },
            onSkip: { [weak self] in
                self?.handleSkip\(\)
            }
        \)
        self.contentViewController = NSHostingController\(rootView: contentView\)

        // 禁止关闭按钮
        self.standardWindowButton\(.closeButton\)?.isEnabled = false

        startCountdown\(\)
    }

    private func startCountdown\(\) {
        var countdown: Int = 3
        countdownTimer = Timer.scheduledTimer\(withTimeInterval: 1.0, repeats: true\) { [weak self] _ in
            guard let self = self else { return }

            countdown -= 1
            print\("⏰ 倒计时: \\\(countdown\)"\)

            if countdown <= 0 {
                self.countdownTimer?.invalidate\(\)
                print\("✓ 倒计时结束，调用完成回调"\)
                self.close\(\)
                self.onCountdownFinish?\(\)
            }
        }
    }

    private func handleCancel\(\) {
        print\("❌ 用户取消休息"\)
        countdownTimer?.invalidate\(\)
        self.close\(\)
        onCancelled?\(\)
    }

    private func handleSkip\(\) {
        print\("⏭️ 用户跳过倒计时"\)
        countdownTimer?.invalidate\(\)
        self.close\(\)
        onCountdownFinish?\(\)
    }

    override var canBecomeKey: Bool {
        return true
    }
}

struct BreakWarningView: View {
    @State private var countdownSeconds: Int
    let onContinue: \(\) -> Void
    let onSkip: \(\) -> Void

    init\(countdownSeconds: Int, onContinue: @escaping \(\) -> Void, onSkip: @escaping \(\) -> Void\) {
        self._countdownSeconds = State\(initialValue: countdownSeconds\)
        self.onContinue = onContinue
        self.onSkip = onSkip
    }

    var body: some View {
        VStack\(spacing: 20\) {
            Spacer\(\)

            Image\(systemName: "clock.fill"\)
                .font\(.system\(size: 50\)\)
                .foregroundColor\(.blue\)

            Text\("休息时间到了"\)
                .font\(.title\)
                .bold\(\)

            Text\("\\\(countdownSeconds\) 秒后开始休息"\)
                .font\(.title2\)
                .foregroundColor\(.secondary\)
                .onAppear {
                    startCountdown\(\)
                }

            Text\("请保存当前工作"\)
                .font\(.body\)
                .foregroundColor\(.secondary\)

            HStack\(spacing: 20\) {
                Button\("继续工作"\) {
                    onContinue\(\)
                }
                .buttonStyle\(.bordered\)
                .frame\(minWidth: 120\)

                Button\("立即休息"\) {
                    onSkip\(\)
                }
                .buttonStyle\(.borderedProminent\)
                .frame\(minWidth: 120\)
            }

            Spacer\(\)
        }
        .padding\(30\)
        .frame\(width: 400, height: 250\)
        .background\(
            RoundedRectangle\(cornerRadius: 20\)
                .fill\(.ultraThinMaterial\)
                .shadow\(radius: 20\)
        \)
    }

    private func startCountdown\(\) {
        Timer.scheduledTimer\(withTimeInterval: 1.0, repeats: true\) { timer in
            if countdownSeconds > 0 {
                countdownSeconds -= 1
            } else {
                timer.invalidate\(\)
            }
        }
    }
}

extension Notification.Name {
    static let cancelBreak = Notification.Name\("cancelBreak"\)
    static let skipCountdown = Notification.Name\("skipCountdown"\)
    static let countdownFinished = Notification.Name\("countdownFinished"\)
}
