import SwiftUI
import AppKit

@main
struct TimeoutApp: App {
    @NSApplicationDelegateAdaptor\(AppDelegate.self\) var appDelegate

    var body: some Scene {
        Settings {
            EmptyView\(\)
        }
    }
}

class AppDelegate: NSObject, NSApplicationDelegate {
    var statusItem: NSStatusItem?
    var timerManager = TimerManager\(\)
    var popover: NSPopover?
    var breakWindow: BreakWindow?
    var warningWindow: BreakWarningWindow?

    func applicationDidFinishLaunching\(_ notification: Notification\) {
        print\("✅ 应用启动成功"\)
        NSApp.setActivationPolicy\(.accessory\)

        statusItem = NSStatusBar.system.statusItem\(withLength: NSStatusItem.variableLength\)
        if let button = statusItem?.button {
            button.title = "🍅"
            button.action = #selector\(togglePopover\)
            button.target = self
        }

        popover = NSPopover\(\)
        popover?.contentSize = NSSize\(width: 300, height: 400\)
        popover?.behavior = .transient
        popover?.contentViewController = NSHostingController\(rootView: TimerView\(timerManager: timerManager\)\)

        NotificationCenter.default.addObserver\(
            forName: .breakDidEnd,
            object: nil,
            queue: .main
        \) { [weak self] _ in
            print\("🔔 收到休息结束通知"\)
            self?.handleBreakEnd\(\)
        }

        NotificationCenter.default.addObserver\(
            forName: .showBreakWarning,
            object: nil,
            queue: .main
        \) { [weak self] _ in
            print\("⚠️ 收到显示警告通知"\)
            self?.showBreakWarning\(\)
        }

        NotificationCenter.default.addObserver\(
            forName: .cancelBreak,
            object: nil,
            queue: .main
        \) { [weak self] _ in
            print\("❌ 收到取消休息通知"\)
            self?.handleCancelBreak\(\)
        }

        NotificationCenter.default.addObserver\(
            forName: .skipCountdown,
            object: nil,
            queue: .main
        \) { [weak self] _ in
            print\("⏭️ 收到跳过倒计时通知"\)
            self?.handleSkipCountdown\(\)
        }

        NotificationCenter.default.addObserver\(
            forName: .countdownFinished,
            object: nil,
            queue: .main
        \) { [weak self] _ in
            print\("⏰ 倒计时结束"\)
            self?.handleCountdownFinished\(\)
        }

        timerManager.onTick = { [weak self] timeString, isActive in
            if let button = self?.statusItem?.button {
                button.title = isActive ? timeString : "🍅"
            }
        }
    }

    func applicationShouldTerminateAfterLastWindowClosed\(_ sender: NSApplication\) -> Bool {
        print\("🚪 应用收到终止询问 - 返回 false"\)
        return false
    }

    func applicationWillTerminate\(_ notification: Notification\) {
        print\("💀 应用即将终止"\)
    }

    @objc func togglePopover\(\) {
        if let popover = popover {
            if popover.isShown {
                popover.performClose\(nil\)
            } else {
                if let button = statusItem?.button {
                    popover.show\(relativeTo: button.bounds, of: button, preferredEdge: .minY\)
                }
            }
        }
    }

    func showBreakWarning\(\) {
        print\("📢 显示警告窗口"\)
        warningWindow = BreakWarningWindow\(
            onCancel: { [weak self] in
                print\("✓ 取消休息回调"\)
                self?.handleCancelBreak\(\)
            },
            onSkip: { [weak self] in
                print\("✓ 跳过倒计时回调"\)
                self?.handleSkipCountdown\(\)
            }
        \)
        warningWindow?.makeKeyAndOrderFront\(nil\)
        NSApp.activate\(ignoringOtherApps: true\)
    }

    func showBreakScreen\(\) {
        print\("💤 显示休息界面"\)
        let isLongBreak = timerManager.completedPomodoros % timerManager.longBreakInterval == 0
        let breakDuration = isLongBreak ? timerManager.longBreakDuration : timerManager.breakDuration
        breakWindow = BreakWindow\(breakDuration: breakDuration\)

        breakWindow?.makeKeyAndOrderFront\(nil\)
        NSApp.activate\(ignoringOtherApps: true\)
    }

    func hideBreakScreen\(\) {
        print\("🙈 隐藏休息界面"\)
        breakWindow?.close\(\)
        breakWindow = nil
    }

    func handleBreakEnd\(\) {
        print\("🏁 处理休息结束"\)
        hideBreakScreen\(\)
        timerManager.resumeFromBreak\(\)
    }

    func handleCancelBreak\(\) {
        print\("↩️ 处理取消休息"\)
        warningWindow?.close\(\)
        warningWindow = nil
        timerManager.cancelBreak\(\)
    }

    func handleSkipCountdown\(\) {
        print\("⏩ 处理跳过倒计时"\)
        warningWindow?.close\(\)
        warningWindow = nil
        if timerManager.currentState == .working {
            timerManager.startBreakNow\(\)
        } else {
            timerManager.startBreak\(\)
        }
        showBreakScreen\(\)
    }

    func handleCountdownFinished\(\) {
        print\("✅ 处理倒计时完成"\)
        warningWindow?.close\(\)
        warningWindow = nil
        if timerManager.currentState == .working {
            timerManager.startBreakNow\(\)
        } else {
            timerManager.startBreak\(\)
        }
        showBreakScreen\(\)
    }

    deinit {
        NotificationCenter.default.removeObserver\(self\)
    }
}
