            startTimer\(\)
            rotateTips\(\)

            // 分阶段动画 - 总共2秒
            withAnimation\(.easeInOut\(duration: 2.0\)\) {
                backgroundOpacity = 1.0
            }

            // 延迟0.5秒后，内容开始淡入（持续1.5秒）
            DispatchQueue.main.asyncAfter\(deadline: .now\(\) + 0.5\) {
                withAnimation\(.easeOut\(duration: 1.5\)\) {
                    contentOpacity = 1.0
                    scale = 1.0
                }
            }
        }
        .onDisappear {
