            HStack\(spacing: 20\) {
                Spacer\(\)

                Button\("退出休息"\) {
                    NotificationCenter.default.post\(name: .breakDidEnd, object: nil\)
                }
                .buttonStyle\(.bordered\)
                Spacer\(\)
            }
            .padding\(.bottom, 20\)
            .opacity\(contentOpacity\)

        case .heavy:
            // 重度模式：显示强制提示，无法退出
            VStack\(spacing: 10\) {
                Text\("⚠️ 强制休息模式"\)
                    .font\(.caption\)
                    .foregroundColor\(.white.opacity\(0.7\)\)
                Text\("休息时间结束后才能继续工作"\)
                    .font\(.caption\)
                    .foregroundColor\(.white.opacity\(0.5\)\)
            }
            .padding\(.bottom, 20\)
            .opacity\(contentOpacity\)
        }
    }

    private var progress: Double {
        guard breakDuration > 0 else { return 0 }
        return currentTime / breakDuration
    }

    private var backgroundView: some View {
        Group {
            switch intensity {
            case .light:
                // 轻度：蓝绿色渐变，30%不透明度
                ZStack {
                    LinearGradient\(
                        colors: [Color.blue.opacity\(0.2\), Color.green.opacity\(0.2\)],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    \)

                    // 添加一些装饰性圆圈
                    Circle\(\)
                        .fill\(
                            RadialGradient\(
                                colors: [Color.blue.opacity\(0.05\), Color.clear],
                                center: .center,
                                startRadius: 50,
                                endRadius: 300
                            \)
                        \)
                        .frame\(width: 400, height: 400\)
                        .position\(x: 200, y: 200\)
                }

            case .medium:
                // 中度：黑色背景，50%不透明度
                ZStack {
                    Color.black.opacity\(0.5\)

                    Circle\(\)
                        .fill\(
                            RadialGradient\(
                                colors: [Color.blue.opacity\(0.1\), Color.clear],
                                center: .center,
                                startRadius: 50,
                                endRadius: 400
                            \)
                        \)
                        .frame\(width: 600, height: 600\)
                        .position\(x: 200, y: 200\)

                    Circle\(\)
                        .fill\(
                            RadialGradient\(
                                colors: [Color.green.opacity\(0.1\), Color.clear],
                                center: .center,
                                startRadius: 50,
                                endRadius: 400
                            \)
                        \)
                        .frame\(width: 500, height: 500\)
                        .position\(x: 800, y: 600\)
                }

            case .heavy:
                // 重度：黑色背景，90%不透明度 + 警告提示
                Color.black.opacity\(0.9\)
                    .overlay\(
                        VStack {
                            Text\("🛑"\)
                                .font\(.system\(size: 80\)\)
                            Text\("强制休息时间"\)
                                .font\(.largeTitle\)
                                .foregroundColor\(.white\)
                                .bold\(\)
                            Text\("请放下鼠标和键盘，让身体放松"\)
                                .font\(.title2\)
                                .foregroundColor\(.white.opacity\(0.8\)\)
                        }
                        .opacity\(0.3\)
                    \)
            }
        }
    }

    private func formatTime\(_ seconds: TimeInterval\) -> String {
        let fromMinutes = Int\(seconds\) / 60
        let fromSecs = Int\(seconds\) % 60
        return String\(format: "%02d:%02d", fromMinutes, fromSecs\)
    }

    private func startTimer\(\) {
        Timer.scheduledTimer\(withTimeInterval: 1.0, repeats: true\) { timer in
            if currentTime > 0 {
                currentTime -= 1
            } else {
                timer.invalidate\(\)
                NotificationCenter.default.post\(name: .breakDidEnd, object: nil\)
            }
        }
    }

    private func startBreathingAnimation\(\) {
        withAnimation {
            breathingPhase = 1.0
        }
    }

    private func nextTip\(\) {
        stretchIndex = \(stretchIndex + 1\) % stretchTips.count
    }

    private func rotateTips\(\) {
        Timer.scheduledTimer\(withTimeInterval: 3.0, repeats: true\) { _ in
            nextTip\(\)
        }
    }
}
